const indexIsInsideBoundaries = (
  index: number,
  boundary1: number,
  boundary2: number,
) =>
  (index >= boundary1 && index <= boundary2) ||
  (index <= boundary1 && index >= boundary2);

/**
 * used by useMouseModifiersOnListSelections hook.
 * Calculates if the index should be selected according to:
 * - keep it if it was selected before without shift.
 * - remove it if it was selected before with shift.
 * - include it if it's being selected now.
 *
 * Returns whether the index should be included in the new list or not.
 */
export const indexShouldBeIncludedInShiftClickedList = (
  index: number,
  newClick: number,
  pivot: number,
  previousLastClick: number,
  wasSelectedBefore: boolean,
): boolean => {
  const isSelectedNow = indexIsInsideBoundaries(index, newClick, pivot);
  const wasSelectedWithShiftBefore = indexIsInsideBoundaries(
    index,
    pivot,
    previousLastClick,
  );

  return isSelectedNow || (wasSelectedBefore && !wasSelectedWithShiftBefore);
};
